* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100%;
  background-color: #0f0f0f;
  font-family: "PP Neue Montreal";
}

img {
  position: absolute;
  width: 100%;
  height: 100%;
  object-fit: cover;
  will-change: transform;
}

.img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
  will-change: transform;
}

h1 {
  color: #dbccc0;
  font-family: "PP Editorial Old";
  font-size: 80px;
  font-weight: 400;
  letter-spacing: -1px;
  line-height: 1;
}

p {
  text-transform: uppercase;
  color: #dbccc0;
  font-size: 14px;
  font-weight: 500;
  line-height: 1;
}

button {
  border: none;
  outline: none;
  text-transform: uppercase;
  font-size: 12px;
  font-weight: 600;
  margin: 0.25em 0;
  padding: 0.3em 0.75em 0.25em 0.75em;
  color: #0f0f0f;
  background-color: #dbccc0;
  border-radius: 2em;
}

section {
  position: relative;
  width: 100vw;
  height: 100vh;
  overflow: hidden;
}

.nav {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 100vw;
  padding: 1em;
  display: flex;
  justify-content: space-between;
  align-items: center;
  z-index: 2;
}

section.projects {
  width: 100vw;
  height: 125vh;
  display: flex;
  gap: 10em;
}

.projects-brief {
  position: absolute;
  width: 25%;
  top: 35%;
  left: 35%;
  transform: translate(-50%, -50%);
  z-index: 2;
}

.projects .col {
  position: relative;
}

.col.projects-cover {
  flex: 1;
  height: 50%;
}

.col.projects-list {
  flex: 2;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 2em;
}

.project {
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 1em;
}

.about {
  display: flex;
  background-color: #68461f;
}

.intro,
.portrait {
  position: relative;
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  padding: 1em;
}

.intro p {
  width: 50%;
  text-align: center;
}

.intro p:nth-child(1) {
  text-decoration: underline;
  margin-bottom: 0.5em;
}

.portrait .portrait-container {
  position: relative;
  width: 100%;
  height: 100%;
}

.banner {
  display: flex;
  justify-content: center;
  align-items: center;
}

.banner-copy {
  position: relative;
  text-align: center;
}

.banner-copy h1 {
  text-transform: uppercase;
}

.banner-copy p:nth-child(3) {
  width: 75%;
  margin: 1em auto;
}

.footer {
  display: flex;
  padding: 1em;
  background-color: #68461f;
}

.footer h1 {
  text-transform: uppercase;
}

.footer .col:nth-child(1) {
  flex: 4;
  height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.footer .col:nth-child(2) {
  flex: 2;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  height: 100%;
}

.shop {
  position: relative;
  width: 100%;
  height: 50%;
}

